import{_ as r,c as t,o as e,a}from"./app.015fbf38.js";const A='{"title":"\u8CFD\u9D3F\u624B\u7684\u72C2\u60F3\u66F2","description":"","frontmatter":{"title":"\u8CFD\u9D3F\u624B\u7684\u72C2\u60F3\u66F2","date":"2018-04-16T07:15:41.000Z","categories":["\u751F\u6D3B\u8A18\u4E8B"]},"headers":[],"relativePath":"Bike/BikeTravel/20180416_\u8CFD\u9D3F\u624B\u7684\u72C2\u60F3\u66F2.md","lastUpdated":1648513476165}',b={},p=a('<p><img src="https://farm1.staticflickr.com/784/41473126761_40ee4944f1.jpg" alt=""><br> \u9D3F\u5B50\u5177\u6709\u826F\u597D\u7684\u65B9\u5411\u611F\u8207\u5C0E\u822A\u80FD\u529B<br> \u6B78\u5DE2\u7684\u7279\u6027\uFF0C\u8B93\u9D3F\u5B50\u80FD\u98DB\u56DE\u81EA\u5DF1\u539F\u4F86\u7684\u4F4F\u8655<br></p><p>\u9D3F\u5B50\u662F\u5C6C\u65BC&quot;\u4E00\u592B\u4E00\u59BB&quot;\u7684\u9CE5\u985E<br> \u7576\u96CC\u6027\u9D3F\u5B50\u7522\u86CB\u5F8C\uFF0C\u96C4\u6027\u9D3F\u5B50\u4E5F\u6703\u5206\u6CCC\u51FA\u4E73\u6C41<br> \u5206\u6524\u9935\u990A\u96DB\u9CE5\uFF0C\u56E0\u6B64\u9D3F\u5B50\u4E5F\u662F\u5FE0\u8AA0\u548C\u53EF\u9760\u7684\u8C61\u5FB5</p><p>\u5982\u4ECA\uFF0C\u9D3F\u5B50\u5DF2\u7D93\u6F14\u8B8A\u70BA\u5177\u6709\u535A\u5F08\u6027\u8CEA\u7684\u7AF6\u8CFD\u884C\u70BA<br> \u4E00\u96BB\u9D3F\u5B50\u4E00\u751F\u53EA\u80FD\u4E0A\u5834\u7AF6\u8CFD\u4E00\u6B21(\u53EF\u80FD\u8CED\u6CE8\u7684\u95DC\u4FC2)<br> \u88AB\u9078\u70BA\u8CFD\u9D3F\u4E0A\u5834\u6BD4\u8CFD\u7684\uFF0C\u662F\u63A1\u7528\u51FA\u751F\u534A\u5E74\u5167\u7684\u5E7C\u9D3F<br> \u9D3F\u5B50\u9700\u901A\u904E\u5169\u95DC\u8CC7\u683C\u8CFD\uFF0C\u4E94\u95DC\u6B63\u5F0F\u9577\u8DDD\u96E2\u6BD4\u8CFD</p><p>\u7136\u800C\u96A8\u6642\u4EE3\u6F14\u8B8A\uFF0C\u5F9E\u539F\u672C\u9678\u4E0A\u7AF6\u8CFD\uFF0C\u8F49\u70BA\u6D77\u4E0A\u7AF6\u8CFD<br> \u5728\u832B\u832B\u5927\u6D77\u770B\u4E0D\u5230\u9678\u5730\u7684\u4E0D\u78BA\u5B9A\u6027\uFF0C\u52A0\u4E0A\u60E1\u6C23\u5019<br> \u6BCF\u5834\u6BD4\u8CFD\uFF0C\u5F80\u5F80\u8B93\u773E\u591A\u9078\u624B\u9D3F\u547D\u55AA\u5916\u6D77\u7576\u4E2D<br> \u5C31\u7B97\u80FD\u6210\u529F\u6B78\u5DE2\uFF0C\u6210\u7E3E\u4E0D\u4F73\u7684\u9D3F\u5B50\u4E5F\u6703\u88AB&quot;\u8655\u6B7B&quot;<br> (\u4E3B\u4EBA\u70BA\u6E1B\u7701\u98DF\u7269\u8207\u7A7A\u9593\u53EA\u597D\u9019\u6A23\u505A)<br> \u8CFD\u5F8C\u7684\u9D3F\u5B50\uFF0C\u82E5\u76F8\u95DC\u8840\u7CFB\u90FD\u6C92\u5F97\u540D\uFF0C\u4E5F\u6703\u906D\u6EC5\u65CF</p><p>\u7D42\u6B78\u767C\u73FE\u9D3F\u5B50\u53EA\u662F\u70BA\u4E86\u6EFF\u8DB3\u4EBA\u535A\u5F08\u7684\u617E\u671B\u8207\u5229\u76CA<br> \u800C\u5FFD\u8996\u6B98\u5BB3\u7121\u8F9C\u9D3F\u5B50\u751F\u547D\uFF0C\u89BA\u5F97\u9D3F\u5B50\u4E0D\u662F\u597D\u7576\u7684</p><p>\u4EE5\u4E0B\u5F15\u7528\u8AD6\u6587<br><a href="https://ndltd.ncl.edu.tw/cgi-bin/gs32/gsweb.cgi?o=dnclcdr&amp;s=id=%22101NHU05665001%22.&amp;searchmode=basic&amp;extralimit=asc=%22%E5%8D%97%E8%8F%AF%E5%A4%A7%E5%AD%B8%22&amp;extralimitunit=%E5%8D%97%E8%8F%AF%E5%A4%A7%E5%AD%B8" target="_blank" rel="noopener noreferrer">\u53F0\u7063\u8CFD\u9D3F\u7684\u793E\u6703\u5B78\u5206\u6790Sociological Analysis of pigeon racing in Taiwan</a></p><p>P.53<br> \u5982\u679C\u5C0D\u4EBA\uF92D\uF96F\uFF0C\u8CFD\u9D3F\u8F38\u6389\u7684\u6642\u5019\uFF0C\u8F38\u6389\u7684\u662F\uF90A\u9322\uFF0C\u4F46\u662F\u5C0D\u9D3F\u5B50\uF92D\uF96F\uFF0C\u7260\u8F38\u6389<br> \u7684\u78BA\u662F\u751F\u547D\u3002\u9D3F\u5B50\u5F9E\u51FA\u751F\u5230\u8A13\uF996\uFF0C\u4E00\u76F4\u5230\u6BD4\u8CFD\uFF0C\u9019\u662F\u4E00\u5834\u5F88\u8271\u8F9B\u7684\u6311\u6230\uFF0C\u4E00\u6279\u9D3F<br> \u5B50\u51FA\uF92D\uFF0C\u4E00\u958B\u59CB\u53EF\u80FD\u6709 20-30 \u96BB\uFF0C\u7136\u800C\u6700\u5F8C\u5269\u4E0B\u7684\u5462\uFF1F\u5C48\u6307\u53EF\uF969\u5427\uFF01\u6709\u7684\u5F9E\u51FA\u751F<br> \u56E0\u70BA\u67D3\u75C5\u800C\uF967\u5E78\u904E\u4E16\uFF0C\u800C\u6709\u7684\u78BA\u662F\u5728\u8A13\uF996\u53CA\u6BD4\u8CFD\u4E2D\u6D88\u901D\uFF0C\u4F46\u80FD\u5920\u5B58\u6D3B\u4E0B\uF92D\u7684\uFF0C\u4E5F<br> \u6709\u53EF\u80FD\u4EE5\u6210\u7E3E\u7684\uF967\uF9E4\u60F3\uFF0C\u800C\u62DB\u81F4\u6BC0\u6EC5\uFF0C\u9019\u5728\u81EA\u7136\u754C\u5C31\u597D\u50CF\u9054\u723E\u6587\u6240\uF96F\u7684\uFF1A\u5F31\u8089\u5F37<br> \u98DF\u3001\u9069\u8005\u751F\u5B58\u3002</p><p>\u56E0\u70BA\u4F60\uF967\uF970\u9D3F\u5B50\u4F60\u6703\u990A\u5F88\u591A\uFF0C\u7260\u53C8\u5F88\u6703\u5403\uFF0C\u4F60\u5C31\u990A\u4E00\u689D\u9D3F\u7A2E\u7684\uF937\uFF0C\u4F46\u662F\u9019\u4E00\u689D<br> \u6210\u7E3E\uF967\u597D\uFF0C\u6211\u5C31\u6574\u689D\u6284\u5BB6\u6EC5\u65CF\uFF0C\u5982\u679C\uF96F \u9019\u4E00\u689D\u662F\u4E00\u865F\u7684\uFF0C\u4E00\u865F\u7684\uF967\u597D\u7684\u8A71\uFF0C\u6574\u500B<br> \u6284\u5BB6\u6EC5\u65CF\uFF0C\u7260\u963F\u516C\u7260\u963F\u7956\uFF0C\u8AB0\uFA26\uF967\u6703\uF9CD\uFF0C\u5168\u90E8\u6DD8\u6C70\uFF0C\uF967\u7BA1\u4F60\u8CB7\u591A\u5C11\uFF0C\uF967\u7BA1\u7260\u6709\u591A<br> \u6602\u8CB4\uFF0C\u5C31\u662F\u5168\u90E8\uFA26\u6DD8\u6C70\uFF0C\u90A3\u56E0\u70BA\u9019\u662F\u73FE\u5BE6\u7684\u3002</p><p>\u8CFD\u9D3F\u7D55\u5C0D\uF967\u662F\u50CF\u7D14\u6BD4\u8CFD\u4E00\u6A23\uFF0C\u9019\u6B21\u6C92\u6709\u4E0B\u6B21\u518D\uF92D\uFF0C\u6BCF\u6B21\u7684\u6BD4\u8CFD\u7684\u8CED\uF90A\uFF0C\u6709\u4E9B\u9D3F\u820D<br> \u53EF\u80FD\u4E00\u671F\u5C31\u9AD8\u9054\u597D\u5E7E\u767E\u842C\u5143\uFF0C\u53EA\u8981 3 \u671F\u30014 \u671F\u6C92\u4E2D\uFF0C\u5C31\u597D\u5E7E\u5343\u842C\uF9BA\uFF0C\u5C31\u7B97\u662F\u6709\u9322<br> \u4E5F\u90FD\u8CED\u8F38\uF9BA\uFF0C\u5982\u679C\u6709\u6B63\u7576\u5DE5\u4F5C\u7684\u98FC\u990A\u8005\u5012\u9084\u597D\uFF0C\u90A3\u5982\u679C\u662F\u5C08\u696D\u7684\u5462\uFF1F\u5E73\u6642\u652F\u6301\u9D3F\u820D<br> \u7684\u904B\u4F5C\u90FD\u9700\u8981\uF90A\u9322\uFF0C\u98FC\uF9BE\u8CBB\u3001\u75AB\u82D7\u8CBB\u3001\u8A13\uF996\u8CBB\u3001\u5831\u540D\u8CBB\u2026\u7B49\uFF0C\u9019\u4E9B\u90FD\u662F\u990A\u9D3F\u8005\u5FC5\u9808<br> \u53BB\u627F\u64D4\u7684\u5F8C\u679C\u3002</p><p>P.61<br> \u990A\u9D3F\uF967\u662F\u4E00\u500B\u4EBA\u7684\u4E8B\u60C5\uFF0C\u9D3F\u5B50\u7684\u8A13\uF996\u3001\u9935\u98DF\u2026\u7B49\uFF0C\u90FD\u662F\u5F88\u56FA\u5B9A\u7684\u6642\u9593\u3002\u6240\u4EE5<br> \u5927\u90E8\u5206\u90FD\u990A\u5728\u5BB6\u5EAD\u9644\u8FD1\uFF0C\u6216\u662F\u5728\u4F4F\u5BB6\uF94C\u4E0A\u6BD4\u8F03\u5BB9\uF9E0\u5C31\u8FD1\u7167\u9867\uFF0C\u76F8\u5C0D\u7684\u5C31\u5F88\u5BB9\uF9E0\u5F71<br> \u97FF\u5230\u5BB6\u5EAD\u7684\u751F\u6D3B\uFF0C\u7136\u800C\u9019\u9EBC\u7E41\u7DD2\u7684\u4F5C\u606F\u7FD2\u6163</p><p>P.64<br> \u4F60\u77E5\u9053\u9D3F\u5B50\u98DB\u56DE\uF92D\u6709\u591A\u53EF\uF98F\uFF0C\u4F60\u53EF\u77E5\u9053\uFF0C\u4F60\uF96F\u7260\u5011\u98DB\u56DE\uF92D\u6709<br> \u516B\u500B\u5C0F\u6642\uFF0C\u62FF\u53BB\u6B78\u9084(\u4EA4\u9D3F)\u7684\u6642\u5019\uFF0C\u7260\u5011\u56DE\uF92D\uFA26\u7528\u722C\u7684\uFF0C\u7260\u56DE\uF92D\u8EAB\u9AD4\uFA26\u662F\u6FD5\u7684\u6C92<br> \uF98A\uFF0C\u771F\u7684\u6C92\u8FA6\u6CD5\u7528\u8D70\u7684\u3002\u9D3F\u5B50\u653E\uF9D3\u5730\uFF0C\uFA26\u7B97\u662F\u8F15\u9B06\uFF0C\u53CD\u800C\u653E\u6D77\u771F\u7684\u53EB\u53EF\uF98F\uFF0C\u771F\u7684<br> \u653E\u6D77\u5F88\u53EF\uF98F</p><p>\u9D3F\u5B50\u70BA\uF9FD\u9EBC\u6703\u8B93\u990A\u9D3F\u6236\u5728\u8CFD\u9D3F\u4E16\u754C\u4E2D\u5982\u7661\u5982\u9189\uFF0C\u7518\u5FC3\u7684\u52AA\uF98A\u73A9\u4E0B\u53BB\uFF0C\u5728\u6700\u5F8C<br> C1 \u544A\u8A34\uF9BA\u7B46\u8005\u4ED6\u5011\u73A9\u9D3F\u4EBA\uFF0C\u5728\u9032\uFA08\u8CFD\u9D3F\u6BD4\u8CFD\u6642\uFF0C\uF967\u53EA\u662F\u5728\u8CC7\uF90A\u4E0A\u7684\u8FFD\u6C42\uFF0C\uF901\u662F<br> \u4E00\u7A2E\u9D3F\u5B50\u7D66\u8207\u4EBA\u7684\u4E00\u7A2E\u80AF\u5B9A\uFF0C\u800C\u76F8\u4FE1\u81EA\u6211\u7684\u990A\u9D3F\u6236\u53EA\u8981\u7528\u5FC3\u4ED8\u51FA\uFF0C\u90A3\u9D3F\u5B50\u662F\u7D55\u5C0D<br> \uF967\u6703\u8B93\u4F60\u5931\u671B\u3002</p><p>P.66<br> \u5728\u98FC\u990A\u9D3F\u5B50\u4E2D\uFF0C\uF967\u4F46\u8981\u7D93\uF98C\u914D\u7A2E\u2192\u8A13\uF996\u2192\u98FC\u990A\u2192\u6BD4\u8CFD\u2026\u7B49\u7E41\u96DC\u7684\u904E\u7A0B\uFF0C\uF901\u662F<br> \u6BCF\u5929\u5FC5\u9808\u9935\u98DF\u3001\u6E05\u6F54\u8207\u8A13\uF996\uFF0C\u7136\u800C A1 \u672C\u8EAB\u81EA\u5DF1\u6709\u5DE5\u4F5C\u4E4B\u5916\uFF0C\u9084\u80FD\u517C\u9867\u5BB6\u5EAD\uFF0C\u8207<br> \u81EA\u5DF1\u7684\u8208\u8DA3\uFF0C\u5BE6\u5728\u5F88\u53B2\u5BB3\uFF0C\u6240\u4EE5\u7B46\u8005\u60F3\u85C9\u7531 A1 \u5C0D\u81EA\u5DF1\u672C\u8EAB\u7684\u5206\u4EAB\uFF0C\uF92D\uF9BA\u89E3\u5BE6\u8E10<br> \u8CFD\u9D3F\u8207\u517C\u9867\u5BB6\u5EAD\u662F\u7528\u751A\u9EBC\u7684\u65B9\u6CD5\uFF0C\u4EE5\u4E0B\u5206\u6210\u4E09\u9EDE\uFF1A</p><ol><li>\u5805\u6301\u4E0B\u53BB\u7684\u6BC5\uF98A\u3002</li><li>\u5C0D\u8208\u8DA3\u7684\u52AA\uF98A\u7372\u7684\u5BB6\uF9E8\u8A8D\u540C\u3002</li><li>\u5DE5\u4F5C\u8207\u8CFD\u9D3F\u4E4B\u9593\u8981\u9054\u5230\u5E73\u8861</li></ol>',14),i=[p];function o(_,c,s,l,n,d){return e(),t("div",null,i)}var f=r(b,[["render",o]]);export{A as __pageData,f as default};
